// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// WIDGET BASE: Tasker Modal - Reopen Tasks
//------------------------------------------------------------------------------------------------------------------------
// 2.8.1 | 2023-04-19 | mmcc | STRY0135713 - Modal showing all comments when clicking the Response Column
//                                      In HTML, created widget to show comments data with gray background on even rows
//                                      In Server script, created widget; pull comments data into an array
//                                      In Client controller, created widget to show a Close button
//                                      Changes made in HTML, Server script and Client controller.
// 2.8.5 | 2023-07-17 | mmcc | DFCT0012086 - "Show All Responses" Hover over the "Close" button, should NOT display 
//                                       the Incorrect toot tip as "Cancel"
//                                      In HTML, update <button> tag's title to use cancelButtonText
//                                      Changes made in HTML.
//
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options) {
	main();

	function main() {
		if (input) {
			if (input.submit == true) {
				// Save edits
				// 		example		var grSelectedTask = new GlideRecord('x_153465_discovert_route_task_instance');
				// 		example		if (grSelectedTask.get(input.taskSysId)) {
				// 		example			new Task_uiAction().uiAction_ReopenTasks(grSelectedTask, input.reopenType);
				// 		example		}

			} else {
				_setDataDefaults();
				_convertToBool(['isModal']);
				_optCopy(['sys_id']);
				_buildMessages();
				_getTaskData();
			}
		} else {
			_setDataDefaults();
			_convertToBool(['isModal']);
			_optCopy(['sys_id']);
			_buildMessages();
			_getTaskData();
		}
	}

	// Use this function to get Messages that will be used in this widget
	function _buildMessages() {
		data.cancelButtonText = gs.getMessage('cancel');

		data.closeButtonText = gs.getMessage('Tasker - Button - Close');

		data.submitButtonText = gs.getMessage('Tasker - Button - Confirm');
		data.submitButtonTitle = gs.getMessage('Tasker - Button - Confirm');

	}

	function _convertToBool(names) {
		names.forEach(function(name) {
			data[name] = data[name] == true || data[name] == 'true';
		});
	}

	function _getTaskData() {
		var record = {
			comments: '',
			label: '',
			svg: ''			
		};

		data.list = [];

		if (data.sys_id == undefined) {
			return;
		} else {
			var grTableData = new GlideRecordSecure(data.table);
			data.assignedTo = {};
			data.canWrite = false;
			data.name = {};
			data.number = {};
			data.state = {};

			if (grTableData.get(data.sys_id)) {
				switch (data.table) {
					// Task table
					case 'x_153465_discovert_route_task_instance':
						data.isBadgeShown = true;
						data.assignedTo.displayValue = grTableData.getElement('assigned_to').getDisplayValue();
						data.assignedTo.label = grTableData.getElement('assigned_to').getLabel();

						data.name.displayValue = grTableData.getElement('short_description').getDisplayValue(50);
						data.name.label = grTableData.getElement('short_description').getLabel();

						data.number.displayValue = grTableData.getElement('number').getDisplayValue();
						data.number.label = grTableData.getElement('number').getLabel();

						data.state.displayValue = grTableData.getElement('state').getDisplayValue();
						data.state.label = grTableData.getElement('state').getLabel();

						// Build an array of Task data for ngRepeat
						if (grTableData.getElement('response').getDisplayValue().length > 0) {
							record.comments = grTableData.getElement('response').getDisplayValue();
							record.label = grTableData.getElement('response').getLabel();
							record.svg = 'ResponseComment16.svg';
							data.list.push(record);
							record = {};
						}

						// Reviewer
						if (grTableData.getElement('comments_dt').getDisplayValue().length > 0) {
							record.comments = grTableData.getElement('comments_dt').getDisplayValue();
							record.label = grTableData.getElement('comments_dt').getLabel();
							record.svg = 'View16.svg';
							data.list.push(record);
							record = {};
						}

						if (grTableData.getElement('rework_comments').getDisplayValue().length > 0) {
							record.comments = grTableData.getElement('rework_comments').getDisplayValue();
							record.label = grTableData.getElement('rework_comments').getLabel();
							record.svg = 'Rework16.svg';
							data.list.push(record);
							record = {};
						}

						if (grTableData.getElement('reopen_comments').getDisplayValue().length > 0) {
							record.comments = grTableData.getElement('reopen_comments').getDisplayValue();
							record.label = grTableData.getElement('reopen_comments').getLabel();
							record.svg = 'Reopen16.svg';
							data.list.push(record);
							record = {};
						}
						break;
					// Action Log table
					case 'x_153465_discovert_discover_tasker_response':
						data.isBadgeShown = false;

						data.assignedTo.displayValue = grTableData.getElement('u_responded_by').getDisplayValue();
						data.assignedTo.label = grTableData.getElement('u_responded_by').getLabel();

						data.name.displayValue = grTableData.getElement('u_task.short_description').getDisplayValue(50);
						data.name.label = grTableData.getElement('u_task.short_description').getLabel();

						data.number.displayValue = grTableData.getElement('u_task_number').getDisplayValue();
						data.number.label = grTableData.getElement('u_task_number').getLabel();

						data.state.displayValue = grTableData.getElement('u_action_taken').getDisplayValue();
						data.state.label = grTableData.getElement('u_action_taken').getLabel();


						var commentType = grTableData.getValue('u_comment_type');
						// in the Action Log table, always use the Response column
						switch(commentType){
							case 'comments_dt':
								// Reviewer
								record.comments = grTableData.getElement('response').getDisplayValue();
								record.label = grTableData.getElement('u_comment_type').getDisplayValue();
								record.svg = 'View16.svg';
								data.list.push(record);
								record = {};
								break;
							case 'reopen_comments':
								record.comments = grTableData.getElement('response').getDisplayValue();
								record.label = grTableData.getElement('u_comment_type').getDisplayValue();
								record.svg = 'Reopen16.svg';
								data.list.push(record);
								record = {};
								break;
							case 'response':
								record.comments = grTableData.getElement('response').getDisplayValue();
								record.label = grTableData.getElement('u_comment_type').getDisplayValue();
								record.svg = 'ResponseComment16.svg';
								data.list.push(record);
								record = {};
								break;
							case 'rework_comments':
								record.comments = grTableData.getElement('response').getDisplayValue();
								record.label = grTableData.getElement('u_comment_type').getDisplayValue();
								record.svg = 'Rework16.svg';
								data.list.push(record);
								record = {};
								break;
						}
						break;
					default:
						break;
				}
			}
		}
	}

	// copy to data from input or options
	function _optCopy(names) {
		names.forEach(function(name) {
			data[name] = input[name] || options[name];
		});
	}

	// Use this function to set defaults
	function _setDataDefaults() {
		data.isModal = (input || {}).isModal || (options || {}).isModal || false;
		data.table = (input || {}).table || (options || {}).table;
	}
})($sp, input, data, options);
